using Financeiro.Domain.Entities; using Financeiro.Domain.Interfaces.Repositories; using Financeiro.Infrastructure.Persistence; using Microsoft.EntityFrameworkCore;
namespace Financeiro.Infrastructure.Repositories; public class PeriodoPagamentoRepository : IPeriodoPagamentoRepository { private readonly AppDbContext _ctx; public PeriodoPagamentoRepository(AppDbContext ctx){_ctx=ctx;} public async Task AddAsync(PeriodoPagamento entity,CancellationToken cancellationToken=default)=> await _ctx.PeriodosPagamento.AddAsync(entity,cancellationToken); public async Task<IReadOnlyList<PeriodoPagamento>> GetAllAsync(CancellationToken cancellationToken=default)=> await _ctx.PeriodosPagamento.Include(p=>p.Despesas).AsNoTracking().ToListAsync(cancellationToken); public Task<PeriodoPagamento?> GetByIdAsync(Guid id,CancellationToken cancellationToken=default)=> _ctx.PeriodosPagamento.Include(p=>p.Despesas).FirstOrDefaultAsync(x=>x.Id==id,cancellationToken); public void Remove(PeriodoPagamento entity)=>_ctx.PeriodosPagamento.Remove(entity); public void Update(PeriodoPagamento entity)=>_ctx.PeriodosPagamento.Update(entity); }
